using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers see all, customers see only their own)
        group.MapGet("/", async (ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();

            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");

            var query = isDispatcher
                ? db.Shipments.AsQueryable()
                : db.Shipments.Where(s => s.CustomerId == user.Id);

            var shipments = await query.OrderByDescending(s => s.CreatedAt).ToListAsync();
            return Results.Ok(shipments.Select(MapToDto));
        });

        // Get single shipment by tracking number
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();

            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();

            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
            if (!isDispatcher && shipment.CustomerId != user.Id) return Results.Forbid();

            return Results.Ok(MapToDto(shipment));
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest request, ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();

            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
            if (!isDispatcher) return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            if (Enum.TryParse<ShipmentStatus>(request.Status, true, out var status))
            {
                shipment.Status = status;
            }
            if (request.Notes is not null) shipment.Notes = request.Notes;
            if (request.EstimatedDelivery.HasValue) shipment.EstimatedDelivery = request.EstimatedDelivery;

            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        });

        // Create shipment (dispatchers only)
        group.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
        {
            var user = await userManager.GetUserAsync(http.User);
            if (user is null) return Results.Unauthorized();

            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
            if (!isDispatcher) return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = request.TrackingNumber ?? $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}",
                Origin = request.Origin,
                Destination = request.Destination,
                CustomerId = request.CustomerId,
                Status = ShipmentStatus.Pending,
                EstimatedDelivery = request.EstimatedDelivery,
                Notes = request.Notes,
                CreatedAt = DateTime.UtcNow
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", MapToDto(shipment));
        });
    }

    private static object MapToDto(Shipment s) => new
    {
        s.Id,
        s.TrackingNumber,
        s.Origin,
        s.Destination,
        Status = s.Status.ToString(),
        s.CreatedAt,
        s.EstimatedDelivery,
        s.Notes,
        s.CustomerId
    };

    public record UpdateStatusRequest(string Status, string? Notes, DateTime? EstimatedDelivery);
    public record CreateShipmentRequest(string? TrackingNumber, string Origin, string Destination, string CustomerId, DateTime? EstimatedDelivery, string? Notes);
}

using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();
        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();

        await db.Database.MigrateAsync();

        // Create roles
        foreach (var role in new[] { "Dispatcher", "Customer" })
        {
            if (!await roleManager.RoleExistsAsync(role))
                await roleManager.CreateAsync(new IdentityRole(role));
        }

        // Create demo dispatcher
        var dispatcher = await userManager.FindByEmailAsync("dispatcher@shiptrack.io");
        if (dispatcher is null)
        {
            dispatcher = new ApplicationUser { UserName = "dispatcher@shiptrack.io", Email = "dispatcher@shiptrack.io", EmailConfirmed = true };
            await userManager.CreateAsync(dispatcher, "Dispatch1!");
            await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
        }

        // Create demo customer
        var customer = await userManager.FindByEmailAsync("customer@example.com");
        if (customer is null)
        {
            customer = new ApplicationUser { UserName = "customer@example.com", Email = "customer@example.com", EmailConfirmed = true };
            await userManager.CreateAsync(customer, "Customer1!");
            await userManager.AddToRoleAsync(customer, "Customer");
        }

        // Seed shipments if empty
        if (!await db.Shipments.AnyAsync())
        {
            db.Shipments.AddRange(
                new Shipment { TrackingNumber = "SHP-20260101-1001", Origin = "New York, NY", Destination = "London, UK", Status = ShipmentStatus.InTransit, CustomerId = customer.Id, EstimatedDelivery = DateTime.UtcNow.AddDays(3), CreatedAt = DateTime.UtcNow.AddDays(-2) },
                new Shipment { TrackingNumber = "SHP-20260101-1002", Origin = "Tokyo, JP", Destination = "Sydney, AU", Status = ShipmentStatus.PickedUp, CustomerId = customer.Id, EstimatedDelivery = DateTime.UtcNow.AddDays(5), CreatedAt = DateTime.UtcNow.AddDays(-1) },
                new Shipment { TrackingNumber = "SHP-20260101-1003", Origin = "Berlin, DE", Destination = "São Paulo, BR", Status = ShipmentStatus.Pending, CustomerId = customer.Id, EstimatedDelivery = DateTime.UtcNow.AddDays(7), CreatedAt = DateTime.UtcNow },
                new Shipment { TrackingNumber = "SHP-20260101-1004", Origin = "Shanghai, CN", Destination = "Los Angeles, CA", Status = ShipmentStatus.Delivered, CustomerId = customer.Id, EstimatedDelivery = DateTime.UtcNow.AddDays(-1), CreatedAt = DateTime.UtcNow.AddDays(-5) },
                new Shipment { TrackingNumber = "SHP-20260101-1005", Origin = "Mumbai, IN", Destination = "Dubai, UAE", Status = ShipmentStatus.OutForDelivery, CustomerId = customer.Id, EstimatedDelivery = DateTime.UtcNow, CreatedAt = DateTime.UtcNow.AddDays(-3) }
            );
            await db.SaveChangesAsync();
        }
    }
}

