+using Microsoft.AspNetCore.Identity;
+using Microsoft.EntityFrameworkCore;
+using ShipmentTracker.Data;
+
+namespace ShipmentTracker.Endpoints;
+
+public static class ShipmentEndpoints
+{
+    public static void MapShipmentEndpoints(this WebApplication app)
+    {
+        var group = app.MapGroup("/api/shipments").RequireAuthorization();
+
+        // Get all shipments (dispatchers see all, customers see only their own)
+        group.MapGet("/", async (ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
+        {
+            var user = await userManager.GetUserAsync(http.User);
+            if (user is null) return Results.Unauthorized();
+
+            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
+
+            var query = isDispatcher
+                ? db.Shipments.AsQueryable()
+                : db.Shipments.Where(s => s.CustomerId == user.Id);
+
+            var shipments = await query.OrderByDescending(s => s.CreatedAt).ToListAsync();
+            return Results.Ok(shipments.Select(MapToDto));
+        });
+
+        // Get single shipment by tracking number
+        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
+        {
+            var user = await userManager.GetUserAsync(http.User);
+            if (user is null) return Results.Unauthorized();
+
+            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
+            if (shipment is null) return Results.NotFound();
+
+            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
+            if (!isDispatcher && shipment.CustomerId != user.Id) return Results.Forbid();
+
+            return Results.Ok(MapToDto(shipment));
+        });
+
+        // Update shipment status (dispatchers only)
+        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest request, ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
+        {
+            var user = await userManager.GetUserAsync(http.User);
+            if (user is null) return Results.Unauthorized();
+
+            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
+            if (!isDispatcher) return Results.Forbid();
+
+            var shipment = await db.Shipments.FindAsync(id);
+            if (shipment is null) return Results.NotFound();
+
+            if (Enum.TryParse<ShipmentStatus>(request.Status, true, out var status))
+            {
+                shipment.Status = status;
+            }
+            if (request.Notes is not null) shipment.Notes = request.Notes;
+            if (request.EstimatedDelivery.HasValue) shipment.EstimatedDelivery = request.EstimatedDelivery;
+
+            await db.SaveChangesAsync();
+            return Results.Ok(MapToDto(shipment));
+        });
+
+        // Create shipment (dispatchers only)
+        group.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db, HttpContext http, UserManager<ApplicationUser> userManager) =>
+        {
+            var user = await userManager.GetUserAsync(http.User);
+            if (user is null) return Results.Unauthorized();
+
+            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
+            if (!isDispatcher) return Results.Forbid();
+
+            var shipment = new Shipment
+            {
+                TrackingNumber = request.TrackingNumber ?? $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}",
+                Origin = request.Origin,
+                Destination = request.Destination,
+                CustomerId = request.CustomerId,
+                Status = ShipmentStatus.Pending,
+                EstimatedDelivery = request.EstimatedDelivery,
+                Notes = request.Notes,
+                CreatedAt = DateTime.UtcNow
+            };
+
+            db.Shipments.Add(shipment);
+            await db.SaveChangesAsync();
+            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", MapToDto(shipment));
+        });
+    }
