@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h3>Shipment Dashboard</h3>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    <button class="btn btn-outline-secondary ms-2" @onclick="LoadShipments">Refresh</button>
</div>

@if (showCreate)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="newOrigin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="newDestination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer ID" @bind="newCustomerId" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="newEstimatedDelivery" />
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-success btn-sm" @onclick="CreateShipment">Create</button>
                <button class="btn btn-secondary btn-sm ms-1" @onclick="() => showCreate = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-2">
        <input class="form-control" placeholder="Filter by tracking #, destination, or status..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                    <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                    <td>
                        <select class="form-select form-select-sm d-inline-block w-auto"
                                value="@s.Status"
                                @onchange="e => UpdateStatus(s.Id, e.Value?.ToString())">
                            <option value="Pending">Pending</option>
                            <option value="PickedUp">Picked Up</option>
                            <option value="InTransit">In Transit</option>
                            <option value="OutForDelivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Cancelled">Cancelled</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showCreate;
    private string newOrigin = string.Empty;
    private string newDestination = string.Empty;
    private string newCustomerId = string.Empty;
    private DateTime? newEstimatedDelivery;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Status.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private void ShowCreateForm()
    {
        showCreate = true;
    }

    private async Task CreateShipment()
    {
        var request = new { Origin = newOrigin, Destination = newDestination, CustomerId = newCustomerId, EstimatedDelivery = newEstimatedDelivery };
        var response = await Http.PostAsJsonAsync("/api/shipments", request);
        if (response.IsSuccessStatusCode)
        {
            showCreate = false;
            newOrigin = newDestination = newCustomerId = string.Empty;
            newEstimatedDelivery = null;
            await LoadShipments();
        }
    }

    private async Task UpdateStatus(int id, string? newStatus)
    {
        if (string.IsNullOrEmpty(newStatus)) return;
        var request = new { Status = newStatus, Notes = (string?)null, EstimatedDelivery = (DateTime?)null };
        var response = await Http.PutAsJsonAsync($"/api/shipments/{id}/status", request);
        if (response.IsSuccessStatusCode)
        {
            await LoadShipments();
        }
    }

    private string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Track My Shipments</PageTitle>

<h3>My Shipments</h3>

<div class="row mb-3">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number..." @bind="searchTracking" />
            <button class="btn btn-outline-primary" @onclick="SearchByTracking">Search</button>
        </div>
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-outline-secondary" @onclick="LoadMyShipments">Refresh All</button>
    </div>
</div>

@if (!string.IsNullOrEmpty(searchError))
{
    <div class="alert alert-warning">@searchError</div>
}

@if (searchResult is not null)
{
    <div class="card mb-4 border-primary">
        <div class="card-header bg-primary text-white">
            Tracking Result: @searchResult.TrackingNumber
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @searchResult.Origin</p>
                    <p><strong>To:</strong> @searchResult.Destination</p>
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadge(searchResult.Status)">@searchResult.Status</span></p>
                </div>
                <div class="col-md-6">
                    <p><strong>Created:</strong> @searchResult.CreatedAt.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @(searchResult.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</p>
                    @if (searchResult.Notes is not null)
                    {
                        <p><strong>Notes:</strong> @searchResult.Notes</p>
                    }
                </div>
            </div>
            @if (searchResult.EstimatedDelivery.HasValue)
            {
                <div class="mt-2">
                    @{ var daysLeft = (searchResult.EstimatedDelivery.Value - DateTime.UtcNow).Days; }
                    @if (daysLeft > 0)
                    {
                        <span class="text-info">📦 Arriving in approximately @daysLeft day(s)</span>
                    }
                    else if (searchResult.Status == "Delivered")
                    {
                        <span class="text-success">✅ Delivered</span>
                    }
                    else
                    {
                        <span class="text-warning">⏰ Delivery may be delayed</span>
                    }
                </div>
            }
        </div>
    </div>
}

<h4>All My Shipments</h4>

@if (shipments is null)
{
    <p><em>Loading...</em></p>
}
else if (!shipments.Any())
{
    <p>You have no shipments yet.</p>
}
else
{
    <div class="row">
        @foreach (var s in shipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h6 class="card-title">@s.TrackingNumber</h6>
                        <p class="card-text mb-1">
                            <small class="text-muted">@s.Origin → @s.Destination</small>
                        </p>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                        @if (s.EstimatedDelivery.HasValue)
                        {
                            <p class="mt-2 mb-0">
                                <small><strong>ETA:</strong> @s.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</small>
                            </p>
                        }
                    </div>
                    <div class="card-footer bg-transparent">
                        <small class="text-muted">Created @s.CreatedAt.ToString("MMM dd, yyyy")</small>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private ShipmentDto? searchResult;
    private string searchTracking = string.Empty;
    private string? searchError;

    protected override async Task OnInitializedAsync()
    {
        await LoadMyShipments();
    }

    private async Task LoadMyShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private async Task SearchByTracking()
    {
        searchError = null;
        searchResult = null;

        if (string.IsNullOrWhiteSpace(searchTracking)) return;

        var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(searchTracking.Trim())}");
        if (response.IsSuccessStatusCode)
        {
            searchResult = await response.Content.ReadFromJsonAsync<ShipmentDto>();
        }
        else
        {
            searchError = "Shipment not found. Please check the tracking number.";
        }
    }

    private string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

